#include <bits/stdc++.h>
using namespace std;

const int N=4e5+10;

int n,m;
int last=1,tot=1,sum[N],f[N],pos[N],c[N];
int dfn[N],num,sz[N],son[N],dep[N],top[N],fa[N];
int path[N],len[N],ans[N];
vector<int> s[N],t[N],e[N];

struct Node{
    int len,fa;
    map<int,int> son;
}st[N];

void extend(int c){
    int p=last,np=last=++tot;
    st[np].len=st[p].len+1;
    for(;p && !st[p].son[c];p=st[p].fa) st[p].son[c]=np;
    if(!p){
        st[np].fa=1;
        return;
    }
    int q=st[p].son[c];
    if(st[q].len==st[p].len+1)
        st[np].fa=q;
    else{
        int nq=++tot;
        st[nq]=st[q],st[nq].len=st[p].len+1;
        st[q].fa=st[np].fa=nq;
        for(;p && st[p].son[c]==q;p=st[p].fa) st[p].son[c]=nq;
    }
}

void dfs(int x){
    sz[x]=1;
    for(int y:e[x]){
        dep[y]=dep[x]+1;
        sum[y]+=sum[x];
        fa[y]=x;
        dfs(y);
        sz[x]+=sz[y];
        if(sz[y]>sz[son[x]]) son[x]=y;
    }
}

void dfs2(int x,int topx){
    top[x]=topx;
    dfn[x]=++num;
    if(son[x])
        dfs2(son[x],topx);
    for(int y:e[x])
        if(y!=son[x])
            dfs2(y,y);
}

void dfs3(int x){
    for(int y:e[x]){
        dfs3(y);
        c[x]+=c[y];
    }
}

bool cmp(int x,int y){
    return dfn[x]<dfn[y];
}

int LCA(int x,int y){
    while(top[x]!=top[y]){
        if(dep[top[x]]<dep[top[y]]) swap(x,y);
        x=fa[top[x]];
    }
    return dep[x]<dep[y]?x:y;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,l,x;i<=n;i++){
        scanf("%d",&l);
        while(l--){
            scanf("%d",&x);
            s[i].push_back(x);
        }
        s[i].push_back(1e4+1);
        scanf("%d",&l);
        while(l--){
            scanf("%d",&x);
            s[i].push_back(x);
        }
    }
    for(int i=1,l,x;i<=m;i++){
        scanf("%d",&l);
        while(l--){
            scanf("%d",&x);
            t[i].push_back(x);
            extend(x);
        }
        extend(1e4+1);
    }
    for(int i=1;i<=m;i++){
        int p=1;
        for(int j:t[i])
            p=st[p].son[j];
        pos[i]=p,sum[p]++,f[p]=t[i].size();
    }
    for(int i=2;i<=tot;i++)
        e[st[i].fa].push_back(i);
    dfs(1);
    dfs2(1,1);
    for(int i=1;i<=n;i++){
        int p=1,cnt=0,l=0;
        for(int j:s[i]){
            while(p>1 && !st[p].son[j]) p=st[p].fa,l=st[p].len;
            if(st[p].son[j]) p=st[p].son[j],l++;
            path[++cnt]=p;
            len[p]=max(len[p],l);
        }
        sort(path+1,path+cnt+1);
        cnt=unique(path+1,path+cnt+1)-path-1;
        sort(path+1,path+cnt+1,cmp);
        int res=0;
        for(int i=1;i<=cnt;i++){
            p=path[i];
            if(st[p].fa){
                c[st[p].fa]++;
                res+=sum[st[p].fa];
            }
            if(i>1){
                if(st[path[i-1]].fa && st[p].fa){
                    int lca=LCA(st[path[i-1]].fa,st[p].fa);
                    c[lca]--;
                    res-=sum[lca];
                }
            }
            if((i==cnt || dfn[p]+sz[p]<=dfn[path[i+1]]) && len[p]>=f[p]){
                c[p]++,c[fa[p]]--;
                res+=sum[p]-sum[fa[p]];
            }
        }
        ans[i]=res;
    }
    dfs3(1);
    for(int i=1;i<=m;i++)
        printf("%d\n",c[pos[i]]);
    for(int i=1;i<=n;i++)
        printf("%d ",ans[i]);
    return 0;
}
